    public static string RegexSeek(this string str, string regex, RegexOptions options = RegexOptions.None)
    {
        try
        {
            var Result = Regex.Match(str, regex, options).Value;
            return string.IsNullOrEmpty(Result) ? null : Result;
        }
        catch (Exception ex)
        {
            Log(ex, "正则匹配第一项出错");
            return null;
        }
    }

