    {
        try
        {
            var Result = regex.Match(str, (int)options).Value;
            return string.IsNullOrEmpty(Result) ? null : Result;
        }
        catch (Exception ex)
        {
            Log(ex, "正则匹配第一项出错");
            return null;
        }
    }

